Real Angular Example — Loading a Dashboard

// dashboard.component.ts
import { Component, OnInit } from '@angular/core';
import { forkJoin } from 'rxjs';
@Component({
selector: 'app-dashboard',
template: `
<div *ngIf="!isLoading">
<div class="stats-card">
<h3>Total Users</h3>
<p>{{ stats?.totalUsers }}</p>
</div>
<div class="stats-card">
<h3>Orders Today</h3>
<p>{{ stats?.ordersToday }}</p>
</div>
<div class="stats-card">
<h3>Revenue</h3>
<p>৳{{ stats?.revenue }}</p>
</div>
<div class="recent-orders">
<h3>Recent Orders</h3>
<div *ngFor="let order of recentOrders">
{{ order.id }} — {{ order.status }}
</div>
</div>
</div>
<div *ngIf="isLoading">Loading dashboard... ⏳</div>
<div *ngIf="error">{{ error }}</div>
`
})
export class DashboardComponent implements OnInit {
stats: any = null;
recentOrders: any[] = [];
isLoading = true;
error = '';
constructor(
private statsService: StatsService,
private orderService: OrderService
) {}
ngOnInit(): void {
// Load BOTH at the same time — wait for both to finish
forkJoin({
stats: this.statsService.getDashboardStats(),
orders: this.orderService.getRecentOrders(5)
}).subscribe({
next: ({ stats, orders }) => {
this.stats = stats;
this.recentOrders = orders;
this.isLoading = false;
},
error: (err) => {
this.error = 'Failed to load dashboard data';
this.isLoading = false;
}
});
}
}

